sql:
SELECT stand_name, area, last_measured_date
FROM forest_stands
ORDER BY last_measured_date DESC;

SELECT volume
FROM total_stand_volume
WHERE stand_id = 1;

SELECT AVG(mass) AS average_carbon_mass
FROM carbon_mass_soil_pool
WHERE stand_id = 1;

external_knowledge:
- Total carbon mass is a critical metric for assessing the carbon sequestration potential of forest stands; 
- Forests play a vital role in the global carbon cycle by absorbing and storing carbon dioxide; 
- Understanding the total carbon mass of different forest stands can inform strategies for maximizing carbon sequestration and mitigating climate change.

sql:
SELECT SUM(volume) AS total_volume
FROM total_stand_volume
WHERE stand_id = 1;

SELECT SUM(mass) AS total_belowground_mass
FROM carbon_mass_belowground_vegetation
WHERE stand_id = 1;

external_knowledge:
- The term 'carbon mass' refers to the amount of carbon stored in a particular component of the forest ecosystem, such as aboveground vegetation, belowground vegetation, litter pool, or soil pool.; 
- 'Growth rate' refers to the rate at which a species grows, typically measured in terms of biomass or volume per unit time.; 
- 'Carbon sequestration rate' refers to the rate at which a species absorbs and stores carbon from the atmosphere.

sql:
SELECT mass
FROM carbon_mass_soil_pool
WHERE species_id = 1 AND stand_id = 0;

SELECT AVG(mass) AS avg_mass
FROM carbon_mass_soil_pool
WHERE stand_id = 1;

SELECT stand_id, volume
FROM total_stand_volume
ORDER BY measurement_date DESC;

SELECT SUM(volume) AS total_volume
FROM stand_volume
WHERE stand_id = 1;
